```csharp
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    public float groundCheckDistance = 0.1f;
    public LayerMask groundLayer;
    private Rigidbody2D rb;

    void Start()
    {
        rb = GetComponent<Rigidbody2D>();
    }

    void Update()
    {
        bool isGrounded = Physics2D.BoxCast(transform.position, new Vector2(0.5f, groundCheckDistance), 0, Vector2.down, 0, groundLayer);
        if (isGrounded)
        {
            rb.bodyType = RigidbodyType2D.Dynamic;
        }
        else
        {
            rb.bodyType = RigidbodyType2D.Kinematic;
        }
    }
}
```

This script checks if the player is touching the ground by casting a small box downwards from the player’s position. Adjust the `groundCheckDistance` and `groundLayer` as needed.

